
def findMaxConsecutiveOnes(nums):
    first = 0
    second = 0
    i = 0
    while i < len(nums):
        if nums[i] == 1:
            second +=1
            if second > first:
                first = second
        else:
            second = 0
        
        i+=1
    
    print(first)
    return first

        

